+    if let Some(stdin) = child.stdin.as_mut() {
+        stdin
+            .write_all(stdout)
+            .unwrap_or_else(|error| panic!("write stdin for {program}: {error}"));
+    } else {
+        panic!("missing stdin pipe for {program}");
+    }
+
+    child
+        .wait_with_output()
+        .unwrap_or_else(|error| panic!("wait for {program}: {error}"))
