+fn replay_roundtrip_events(json: &str) -> Vec<InputEvent> {
+    let mut player = ReplayPlayer::from_json(json).expect("replay JSON should decode");
+    player.play();
+
+    let mut events = Vec::new();
+    while let Some((_offset, event)) = player.advance_input() {
+        events.push(event);
+    }
+    events
+}
