+fn first_mismatch_index(expected: &[InputEvent], observed: &[InputEvent]) -> Option<usize> {
+    expected
+        .iter()
+        .zip(observed.iter())
+        .position(|(left, right)| left != right)
+        .or_else(|| {
+            if expected.len() == observed.len() {
+                None
+            } else {
+                Some(expected.len().min(observed.len()))
+            }
+        })
+}
