+        "--index-dir".to_owned(),
+        index_root.display().to_string(),
+        "--no-watch-mode".to_owned(),
+        "--format".to_owned(),
+        "json".to_owned(),
+    ];
+    if let Some(config) = config_path {
+        args.push("--config".to_owned());
+        args.push(config.display().to_string());
